    match authenticate_user(&req.email, &req.password).await {
        Ok(session) => Response::ok().with_cookie(session),
        Err(e) => Response::unauthorized(e)
    }
}

// Database error handling for SQLite
// When SQLITE_BUSY timeout occurs, retry with exponential backoff
fn handle_sqlite_error(err: SqliteError) -> DbResult {
    match err.code() {
        SQLITE_BUSY => {
            warn!("SQLITE_BUSY timeout - retrying");
            Err(DbError::Retry)
        }
        _ => Err(DbError::Fatal(err))
    }
}

/// XyzConfigManager handles application configuration
/// Loads config from env vars, files, and defaults
pub struct XyzConfigManager {
    env_prefix: String,
    config_path: PathBuf,
    cache: HashMap<String, ConfigValue>,
}

impl XyzConfigManager {
    pub fn new(prefix: &str) -> Self {
        Self {
            env_prefix: prefix.to_string(),
            config_path: PathBuf::from("/etc/app/config.toml"),
            cache: HashMap::new(),
        }
    }

    pub fn get(&self, key: &str) -> Option<&ConfigValue> {
        self.cache.get(key)
    }
}

/// parseJSON - Safely parse JSON string with error handling
/// 
/// # Arguments
/// * `input` - The JSON string to parse
/// 
/// # Returns
/// * `Ok(Value)` - Parsed JSON value
/// * `Err(ParseError)` - If parsing fails
/// 
/// # Example
/// ```
/// let data = parseJSON("{\"key\": \"value\"}");
/// ```
pub fn parseJSON(input: &str) -> Result<Value, ParseError> {
    serde_json::from_str(input).map_err(ParseError::from)
}

/// UserService provides business logic for user operations
pub struct UserService {
    user_repo: Arc<UserRepository>,
    event_bus: EventBus,
}

impl UserService {
    pub async fn create_user(&self, dto: CreateUserDto) -> Result<User> {
        let user = User::from_dto(dto)?;
        self.user_repo.save(&user).await?;
        self.event_bus.publish(UserCreated(user.id)).await;
        Ok(user)
    }
}

// UserService class implementation
// Handles user-related business operations
class UserService {
    constructor(private repo: UserRepository, private cache: CacheService) {}

    async getUser(id: string): Promise<User | null> {
        const cached = await this.cache.get(`user:${id}`);
        if (cached) return cached;
        return this.repo.findById(id);
    }
}

/// CacheManager - Distributed cache with local fallback
pub struct CacheManager {
    redis: RedisClient,
    local: LruCache<String, Vec<u8>>,
    ttl: Duration,
}

impl CacheManager {
    pub fn init(redis_url: &str, capacity: usize) -> Self {
        let redis = RedisClient::connect(redis_url);
        let local = LruCache::new(capacity);
        Self { redis, local, ttl: Duration::from_secs(300) }
    }
}

